def _save_deterministic_xlsx(wb: Workbook, out_path: Path) -> None:
    """Save a workbook with reproducible zip metadata for byte-stable fixtures."""
    import io
    import zipfile

    buf = io.BytesIO()
    wb.save(buf)
    buf.seek(0)

    fixed_dt = (2020, 1, 1, 0, 0, 0)
    with zipfile.ZipFile(buf, "r") as zin, zipfile.ZipFile(
        out_path, "w", compression=zipfile.ZIP_DEFLATED
    ) as zout:
        for item in sorted(zin.infolist(), key=lambda info: info.filename):
            data = zin.read(item.filename)
            new_info = zipfile.ZipInfo(item.filename, date_time=fixed_dt)
            new_info.compress_type = item.compress_type
            new_info.comment = item.comment
            new_info.extra = item.extra
            new_info.create_system = item.create_system
            new_info.flag_bits = item.flag_bits
            new_info.extract_version = item.extract_version
            new_info.external_attr = item.external_attr
            zout.writestr(new_info, data)


